DECLARE @COEF  SMALLINT
DECLARE @BRANCH  SMALLINT
DECLARE @DEPARTMENT SMALLINT
DECLARE @STATUS   SMALLINT
DECLARE @FROMDEMTYPE  SMALLINT
DECLARE @BDGLNTYPE  SMALLINT
DECLARE @EMDEMLNREF     INT
DECLARE @TRNET          FLOAT
DECLARE @TRCURR         SMALLINT
SELECT @DT          = I.DATE_,
       @MONTH       = I.MONTH_,
       @YEAR        = I.YEAR_,
       @SIGN        = I.SIGN,
       @ACCOUNTREF  = I.ACCOUNTREF,
       @CENTERREF   = I.CENTERREF,
       @TRCODE      = I.TRCODE,
       @ACCOUNTCODE = I.ACCOUNTCODE,
       @DEBIT       = I.DEBIT,
