       @EMUDEBIT    = I.EMUDEBIT,
       @EMUCREDIT   = I.EMUCREDIT,
       @CANCELLED   = I.CANCELLED,
       @REPORTNET   = I.REPORTNET,
       @INFIDX        = I.INFIDX,
       @NOTINFLATED   = I.NOTINFLATED,
       @NOTCALCULATED = I.NOTCALCULATED,
       @AMNT        = I.AMNT,
       @BRANCH      = I.BRANCH,
       @DEPARTMENT  = I.DEPARTMENT,
       @STATUS      = I.STATUS,
       @FROMDEMTYPE = I.FROMDEMTYPE ,
       @BDGLNTYPE   = I.BDGTLINETYPE,
       @EMDEMLNREF  = I.EMDEMLNREF,
       @TRNET       = I.TRNET,
       @TRCURR      = I.TRCURR FROM INSERTED I
EXECUTE LG_UPDATE_EMTRANS_323_02 @DT, @SIGN, @ACCOUNTREF, 0, @TRCODE, @ACCOUNTCODE, @DEBIT, @CREDIT, @EMUDEBIT, @EMUCREDIT, @CANCELLED, @REPORTNET, @AMNT, 1
        , @INFIDX, @NOTINFLATED, @NOTCALCULATED, @BRANCH, @DEPARTMENT, @STATUS, @FROMDEMTYPE, @BDGLNTYPE, @EMDEMLNREF
        , @MONTH, @YEAR, @TRNET, @TRCURR
SELECT @DT          = D.DATE_,
       @MONTH       = D.MONTH_,
       @YEAR        = D.YEAR_,
       @SIGN        = D.SIGN,
       @ACCOUNTREF  = D.ACCOUNTREF,
       @CENTERREF   = D.CENTERREF,
       @TRCODE      = D.TRCODE,
       @ACCOUNTCODE = D.ACCOUNTCODE,
       @DEBIT       = D.DEBIT,
       @CREDIT      = D.CREDIT,
       @EMUDEBIT    = D.EMUDEBIT,
       @EMUCREDIT   = D.EMUCREDIT,
       @CANCELLED   = D.CANCELLED,
       @REPORTNET   = D.REPORTNET,
       @INFIDX        = D.INFIDX,
       @NOTINFLATED   = D.NOTINFLATED,
       @NOTCALCULATED = D.NOTCALCULATED,
       @AMNT        = D.AMNT,
       @BRANCH      = D.BRANCH,
       @DEPARTMENT  = D.DEPARTMENT,
       @STATUS      = D.STATUS,
       @FROMDEMTYPE = D.FROMDEMTYPE ,
       @BDGLNTYPE   = D.BDGTLINETYPE,
       @EMDEMLNREF  = D.EMDEMLNREF,
       @TRNET       = D.TRNET,
       @TRCURR      = D.TRCURR FROM DELETED D
EXECUTE LG_UPDATE_EMTRANS_323_02 @DT, @SIGN, @ACCOUNTREF, 0, @TRCODE, @ACCOUNTCODE, @DEBIT, @CREDIT, @EMUDEBIT, @EMUCREDIT, @CANCELLED, @REPORTNET, @AMNT, -1
        , @INFIDX, @NOTINFLATED, @NOTCALCULATED, @BRANCH, @DEPARTMENT, @STATUS, @FROMDEMTYPE, @BDGLNTYPE, @EMDEMLNREF
        , @MONTH, @YEAR, @TRNET, @TRCURR
